import { syntaxTree } from '@codemirror/language';
import { RangeSetBuilder } from '@codemirror/state';
import { ViewPlugin } from '@codemirror/view';
import type {
  Decoration,
  DecorationSet,
  EditorView,
  ViewUpdate,
} from '@codemirror/view';

import { errorMark, valueMark } from './decoration-marks.js';

/**
 * Create a range set with decorations for all the filter values.
 * @internal
 */
export function createFilterValueDecorations(view: EditorView) {
  const builder = new RangeSetBuilder<Decoration>();

  for (const { from, to } of view.visibleRanges) {
    const tree = syntaxTree(view.state);
    tree.iterate({
      from,
      to,
      enter: (node) => {
        if (node.type.is('FilterValue')) {
          const { from: valueFrom, to: valueTo } = node;
          if (tree.resolveInner(node.to, -1).parent?.name === '⚠') {
            builder.add(valueFrom, valueTo, errorMark);
            return;
          }
          builder.add(valueFrom, valueTo, valueMark);

          return false;
        }
      },
    });
  }

  return builder.finish();
}

/**
 * View plugin to wrap all filter values in spans.
 * @internal
 */
export const FilterValueDecorationPlugin = ViewPlugin.fromClass(
  class {
    decorations: DecorationSet;

    constructor(view: EditorView) {
      this.decorations = createFilterValueDecorations(view);
    }

    update(update: ViewUpdate) {
      if (update.docChanged) {
        this.decorations = createFilterValueDecorations(update.view);
      }
    }
  },
  {
    decorations: (view) => view.decorations,
  },
);
